import React, { useEffect, useState } from "react";
import Sidebar from "../components/Sidebar";
import Navbar from "../components/Navbar";
import API from "../api";

function AppointmentPage() {
  const user = JSON.parse(localStorage.getItem("user"));
  const isAdmin = user?.role === "admin";

  const [appointments, setAppointments] = useState([]);
  const [form, setForm] = useState({
    doctor_name: "",
    specialization: "",
    appointment_date: "",
    notes: ""
  });

  useEffect(() => {
    fetchAppointments();
    // eslint-disable-next-line
  }, []);

  const fetchAppointments = async () => {
    try {
      let url = "/appointments";
      if (!isAdmin && user?.email) {
        url = `/appointments?email=${user.email}`;
      }
      const res = await API.get(url);
      setAppointments(res.data);
    } catch (error) {
      console.error("Failed to fetch appointments");
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      await API.post("/appointments", {
        patient_name: user?.name || "",
        patient_email: user?.email || "",
        doctor_name: form.doctor_name,
        specialization: form.specialization,
        appointment_date: form.appointment_date,
        notes: form.notes
      });

      alert("Appointment request submitted successfully");
      setForm({
        doctor_name: "",
        specialization: "",
        appointment_date: "",
        notes: ""
      });
      fetchAppointments();
    } catch (error) {
      alert(error.response?.data?.error || "Failed to submit appointment");
    }
  };

  const updateStatus = async (id, status) => {
    try {
      await API.put(`/appointments/${id}`, { status });
      fetchAppointments();
    } catch (error) {
      alert("Status update failed");
    }
  };

  return (
    <div className="dashboard-layout">
      <Sidebar role={isAdmin ? "admin" : "patient"} />

      <div className="main-content">
        <Navbar
          title="Appointments"
          subtitle={
            isAdmin
              ? "Manage patient appointment requests"
              : "Request an appointment with a doctor"
          }
        />

        {!isAdmin && (
          <div className="form-box mb-4">
            <h4>Book Appointment</h4>
            <form onSubmit={handleSubmit}>
              <div className="row mt-3">
                <div className="col-md-6 mb-3">
                  <label>Doctor Name</label>
                  <input
                    type="text"
                    className="form-control"
                    value={form.doctor_name}
                    onChange={(e) =>
                      setForm({ ...form, doctor_name: e.target.value })
                    }
                    required
                  />
                </div>

                <div className="col-md-6 mb-3">
                  <label>Specialization</label>
                  <input
                    type="text"
                    className="form-control"
                    value={form.specialization}
                    onChange={(e) =>
                      setForm({ ...form, specialization: e.target.value })
                    }
                    required
                  />
                </div>

                <div className="col-md-6 mb-3">
                  <label>Appointment Date</label>
                  <input
                    type="date"
                    className="form-control"
                    value={form.appointment_date}
                    onChange={(e) =>
                      setForm({ ...form, appointment_date: e.target.value })
                    }
                    required
                  />
                </div>

                <div className="col-md-6 mb-3">
                  <label>Notes</label>
                  <input
                    type="text"
                    className="form-control"
                    value={form.notes}
                    onChange={(e) =>
                      setForm({ ...form, notes: e.target.value })
                    }
                    placeholder="Optional notes"
                  />
                </div>
              </div>

              <button className="btn btn-premium">Request Appointment</button>
            </form>
          </div>
        )}

        <div className="row g-4">
          {appointments.length === 0 ? (
            <div className="col-12">
              <div className="empty-card">
                <h4>No Appointments Found</h4>
                <p>Your appointment requests will appear here.</p>
              </div>
            </div>
          ) : (
            appointments.map((item) => (
              <div className="col-md-6 col-lg-4" key={item.id}>
                <div className="appointment-card">
                  <h5>{item.patient_name}</h5>
                  <p>
                    <strong>Doctor:</strong> {item.doctor_name}
                  </p>
                  <p>
                    <strong>Specialization:</strong> {item.specialization}
                  </p>
                  <p>
                    <strong>Date:</strong> {item.appointment_date}
                  </p>
                  <p>
                    <strong>Status:</strong>{" "}
                    <span className={`status-badge ${item.status?.toLowerCase()}`}>
                      {item.status || "Pending"}
                    </span>
                  </p>
                  <p>
                    <strong>Notes:</strong> {item.notes || "N/A"}
                  </p>

                  {isAdmin && (
                    <div className="d-flex gap-2 mt-3">
                      <button
                        className="btn btn-success btn-sm"
                        onClick={() => updateStatus(item.id, "Approved")}
                      >
                        Approve
                      </button>
                      <button
                        className="btn btn-danger btn-sm"
                        onClick={() => updateStatus(item.id, "Rejected")}
                      >
                        Reject
                      </button>
                    </div>
                  )}
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

export default AppointmentPage;
